package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.Gson;
import com.google.gson.FieldNamingStrategy;
import com.google.gson.LongSerializationPolicy;
import com.google.gson.ToNumberStrategy;
import com.google.gson.internal.Excluder;

import java.lang.reflect.Constructor;
import java.util.List;
import java.util.Map;

class GsonSerializeNullsTest {

  @Test
  void testSerializeNulls_DefaultConstructor() {
    Gson gson = new Gson();
    // Default Gson serializeNulls should be false as per DEFAULT_SERIALIZE_NULLS
    assertFalse(gson.serializeNulls());
  }

  @Test
  void testSerializeNulls_CustomTrue() throws Exception {
    // Using reflection to create Gson instance with serializeNulls = true
    Gson gson = createGsonWithSerializeNulls(true);
    assertTrue(gson.serializeNulls());
  }

  @Test
  void testSerializeNulls_CustomFalse() throws Exception {
    // Using reflection to create Gson instance with serializeNulls = false
    Gson gson = createGsonWithSerializeNulls(false);
    assertFalse(gson.serializeNulls());
  }

  private Gson createGsonWithSerializeNulls(boolean serializeNulls) throws Exception {
    Class<Gson> gsonClass = Gson.class;

    Constructor<Gson> constructor = gsonClass.getDeclaredConstructor(
        Excluder.class,
        FieldNamingStrategy.class,
        Map.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        LongSerializationPolicy.class,
        String.class,
        int.class,
        int.class,
        List.class,
        List.class,
        List.class,
        ToNumberStrategy.class,
        ToNumberStrategy.class,
        List.class
    );
    constructor.setAccessible(true);

    return constructor.newInstance(
        Excluder.DEFAULT,          // Excluder - use default instance instead of null
        FieldNamingStrategy.IDENTITY, // FieldNamingStrategy - use default instead of null
        Map.of(),                  // Map<Type, InstanceCreator<?>> - empty map instead of null
        serializeNulls,
        false,                    // complexMapKeySerialization
        false,                    // generateNonExecutableGson
        true,                     // htmlSafe
        false,                    // prettyPrinting
        false,                    // lenient
        false,                    // serializeSpecialFloatingPointValues
        true,                     // useJdkUnsafe
        LongSerializationPolicy.DEFAULT, // LongSerializationPolicy - default instead of null
        null,                     // datePattern
        0,                        // dateStyle
        0,                        // timeStyle
        List.of(),                // builderFactories - empty list instead of null
        List.of(),                // builderHierarchyFactories - empty list instead of null
        List.of(),                // factoriesToBeAdded - empty list instead of null
        ToNumberStrategy.DEFAULT_OBJECT_TO_NUMBER_STRATEGY, // objectToNumberStrategy - default instead of null
        ToNumberStrategy.DEFAULT_NUMBER_TO_NUMBER_STRATEGY, // numberToNumberStrategy - default instead of null
        List.of()                 // reflectionFilters - empty list instead of null
    );
  }
}
